# Category: xxe

require 'sweet-xml'  # or any other parser lib of your choice
use Rack::CommonLogger
use Phoenix.Rack.Handler

def call(env)
    req = env["HTTP_RAW_POST_DATA"]
    xml = SweetXml.parse(req).children[0]

    # Parse the xml
    name = xml['name'].value  # Get the name of the user
    company = xml['company']['name'].value  # Get the name of their company

    [200, {'Content-Type' => 'text/plain'}, [name, company]]
end